#!/usr/bin/env python3
"""apply_overlord_faces.py — inject Sensory Over-lord face assets a1000-a1005 (raw base64) into assets/assets.json."""
import json,os,sys
root=os.path.dirname(os.path.abspath(__file__))
ap=os.path.join(root,"assets/assets.json")
if not os.path.exists(ap): sys.exit("[apply] assets/assets.json not found")
assets=json.load(open(ap))
faces={"a1000": "", "a1001": "", "a1002": "", "a1003": "", "a1004": "", "a1005": ""}
assets.update(faces)
json.dump(assets,open(ap,"w"))
print("[apply] wrote Over-lord faces a1000-a1005")
